#include <stdio.h>
int main() {
    int n;
    scanf("%d", &n);
    int count = 0;
    for (int k = 2; k <= n; k++) {
        int p = 1;
        for (int i = 2; i * i <= k; i++) {
            if (k % i == 0) { p = 0; break; }
        }
        if (p) count++;
    }
    printf("%d\n", count);
    return 0;
}
